// Falsy in if conditions
if (0)         { /* won't run */ }
if ("")        { /* won't run */ }
if (null)      { /* won't run */ }
if (undefined) { /* won't run */ }

// Truthy in if conditions
if ("0")  { /* WILL run — non-empty string */ }
if ([])   { /* WILL run — empty array is truthy! */ }
if ({})   { /* WILL run — empty object is truthy! */ }

// Double negation trick — convert to boolean
