class Animal {
  // Private field (ES2022)
  #name;
  #sound;

  constructor(name, sound) {
    this.#name = name;
    this.#sound = sound;
  }

  // Getter
  get name() { return this.#name; }

  // Instance method
  speak() {
    return `${this.#name} says ${this.#sound}!`;
  }

  // Static method — called on the class, not instances
  static create(name, sound) {
    return new Animal(name, sound);
  }
}

const dog = new Animal("Rex", "woof");
console.log(dog.speak());        // "Rex says woof!"
console.log(dog.name);           // "Rex"
// console.log(dog.#name);       // ❌ SyntaxError — private!

const cat = Animal.create("Whiskers", "meow");

class Dog extends Animal {
  #tricks = [];

  constructor(name) {
    super(name, "woof"); // must call super first
  }

  learn(trick) {
    this.#tricks.push(trick);
    return this;
  }

  showTricks() {
    if (this.#tricks.length === 0) return `${this.name} knows no tricks.`;
    return `${this.name} knows: ${this.#tricks.join(", ")}`;
  }

  // Override parent method
  speak() {
    return super.speak() + " (Good dog!)";
  }
}

const buddy = new Dog("Buddy");
buddy.learn("sit").learn("shake").learn("roll over");
console.log(buddy.showTricks()); // "Buddy knows: sit, shake, roll over"
console.log(buddy.speak());      // "Buddy says woof! (Good dog!)"
console.log(buddy instanceof Dog);    // true
console.log(buddy instanceof Animal); // true

