const timer = {
  count: 0,
  // Regular function — 'this' is lost in callback
  startBroken() {
    setInterval(function() {
      this.count++; // ❌ 'this' is Window, not timer!
    }, 1000);
  },
  // Arrow function — 'this' is inherited from surrounding scope
  start() {
    setInterval(() => {
      this.count++; // ✅ 'this' is timer object
      console.log(this.count);
    }, 1000);
  }
};

function introduce(greeting, punctuation) {
  return `${greeting}, I'm ${this.name}${punctuation}`;
}

const person = { name: "Alice" };

// call() — invoke immediately, args listed separately
introduce.call(person, "Hello", "!");   // "Hello, I'm Alice!"

// apply() — invoke immediately, args as array
introduce.apply(person, ["Hi", "."]); // "Hi, I'm Alice."

// bind() — returns a NEW function with 'this' locked
const aliceIntro = introduce.bind(person);
aliceIntro("Hey", "?"); // "Hey, I'm Alice?"

