// Promise.all — wait for ALL, fail fast on any rejection
const [users, posts, comments] = await Promise.all([p1, p2, p3]);

// Promise.allSettled — wait for ALL, never fails
const results = await Promise.allSettled([p1, p2, p3]);
results.forEach(r => {
  if (r.status === "fulfilled") console.log(r.value);
  else console.error(r.reason);
});

// Promise.race — first one wins (resolved or rejected)
const first = await Promise.race([p1, p2, p3]);

// Promise.any — first RESOLVED wins (ignores rejections)
const fastest = await Promise.any([p1, p2, p3]);

